    raise exception using
      errcode = '42P01',
      message = 'JAGRUKSETU_HANDOFF_ACTIONS_MIGRATION_REQUIRED';
  end if;

  if not exists (
    select 1
    from governance.reference_sources
    where url = 'https://dm.mcgm.gov.in/assets/pdf/Final%20updated%20Final%20Connect%20Diary%202021.07.07.2021.pdf'
  ) then
    raise exception using
      errcode = '55000',
      message = 'BMC_REFERENCE_SOURCE_REQUIRED';
  end if;

  if not exists (
    select 1 from governance.authorities where id = '3fabe3b8-47cf-58fe-a59c-bb34bd02322a'
  ) or not exists (
    select 1 from governance.local_bodies where id = 'fa1e71b4-01e3-5e72-92e8-1476eec1adcd'
  ) or not exists (
    select 1 from governance.departments where id = 'c3cb4f48-502e-572c-9c85-5d200b886ac8'
