    where id = '4235f4f1-d01d-5a40-93cb-5aa2a5537945'
  ) then
    raise exception using
      errcode = '55000',
      message = 'BMC_V1_ROUTE_TARGET_PREREQUISITE_MISSING';
  end if;

  if (
    select count(*)
    from routing.issue_categories
    where category_purpose = 'taxonomy_subcategory'
  ) <> 340 then
    raise exception using
      errcode = '55000',
      message = 'JAGRUKSETU_TAXONOMY_SEED_REQUIRED';
  end if;

  if (
    select count(*)
    from governance.wards
    where local_body_id = 'fa1e71b4-01e3-5e72-92e8-1476eec1adcd'
      and ward_number = any(array['A', 'B', 'C', 'D', 'E', 'F/S', 'F/N', 'G/S', 'G/N', 'H/E', 'H/W', 'K/S', 'K/N', 'K/W', 'P/S', 'P/E', 'P/W', 'R/S', 'R/C', 'R/N', 'L', 'M/E', 'M/W', 'N', 'S', 'T']::text[])
  ) <> 26 then
    raise exception using
      errcode = '55000',
      message = 'BMC_OPERATIONAL_WARD_COUNT_INVALID';
  end if;

  if (
    select count(*)
    from routing.ward_issue_contacts as contact
    inner join governance.wards as ward on ward.id = contact.ward_id
    inner join routing.issue_categories as category on category.id = contact.category_id
    where ward.local_body_id = 'fa1e71b4-01e3-5e72-92e8-1476eec1adcd'
      and category.code = any(array['blocked_drain', 'broken_streetlight', 'encroachment', 'fallen_tree', 'garbage_dump', 'illegal_construction', 'missed_sweeping', 'mosquito_breeding', 'open_manhole', 'pothole', 'sewage_overflow', 'water_leakage']::text[])
